tool_calls:
# Create the report by joining on department_id
{
  # Read departments into an array
  awk -F, 'NR>1 {dept[$1]=$2}' /data/departments.csv

  # Process employees and join with departments
  awk -F, '
    BEGIN {
      # Read departments first
      while ((getline < "/data/departments.csv") > 0) {
        if (NR > 1) {  # Skip header
          split($0, fields, ",")
          dept[fields[1]] = fields[2]
        }
      }
      print "name,department_name,salary"
    }
    FNR==1 && NR>1 {next}  # Skip header in employees.csv
    {
      print $1 "," dept[$2] "," $3
    }
  ' /data/employees.csv > /data/report.csv
}

# Print the result
cat /data/report.csv

